class TreeAncestor {
    int[][] dp;

    public TreeAncestor(int n, int[] parent) {
        dp = new int[n][20];
        for (int i = 0; i < n; i++) dp[i][0] = parent[i];
        for (int k = 1; k < 20; k++)
            for (int i = 0; i < n; i++)
                dp[i][k] = dp[i][k - 1] == -1 ? -1 : dp[dp[i][k - 1]][k - 1];
    }

    public int getKthAncestor(int node, int k) {
        for (int i = 0; i < 20; i++) {
            if ((k & (1 << i)) != 0) {
                node = dp[node][i];
                if (node == -1) return -1;
            }
        }
        return node;
    }
}
